import { Component, Event, EventEmitter, h, Prop } from '@stencil/core';

@Component({
  tag: 'wdpr-media-player-control-captions-toggle',
  shadow: true,
})
export class WdprMediaPlayerControlCaptionsToggle {
  @Prop() enabled = false;
  @Prop() isDisabled = false;
  @Event({ bubbles: true, composed: true }) wdprCaptionsToggle!: EventEmitter<void>;

  private _onClick = () => {
    this.wdprCaptionsToggle.emit();
  };

  render() {
    return (
      <button class={containerButtonClasses} aria-label="Toggle closed captions" aria-pressed={this.enabled} disabled={this.isDisabled} onClick={this._onClick}>
        {this.enabled ? (
          <wdpr-icon-library size="medium" icon="media-closed-caption-on" decorative={true} />
        ) : (
          <wdpr-icon-library size="medium" icon="video-closed-captioning" decorative={true} />
        )}
      </button>
    );
  }
}

const containerButtonClasses = `
    cursor-pointer p-025 flex items-center rounded-pill border border-transparent
    focus:outline-none focus-visible:outline-037 focus-visible:outline-stroke-actionable-alt-focused focus-visible:outline-solid focus-visible:outline-offset-2
    text-icon-actionable-inverse-default bg-transparent
    disabled:cursor-not-allowed disabled:opacity-500
`;
